import Navbar from "../components/Navbar";
import "../styles/Login.css";
import avatar from "../assets/images/avatar.png";

function Signup() {
  return (
    <div>
        <div className="login-container">
            <Navbar />
            <div className="login-content">
                <div className="login">
                    <img src={avatar} alt="avatar" className="avatar"/>
                    <input className="correo" placeholder="Correo" />
                    <input className="contraseña" placeholder="Password" type="password" />
                    <select className="facultades">
                        <option value="">Selecciona una facultad</option>
                        <option value="Ingenieria y Ciencias Basicas">Ingenieria y Ciencias Basicas</option>
                        <option value="Comunicacion">Comunicación</option>
                        <option value="Negocios Internacionales">Negocios Internacionales</option>
                    </select>
                    <button className="ingresar">Ingresar</button>
                </div>
                <p className="texto">Welcome Back</p>
            </div>
        </div>
    </div>
  );
}

export default Signup;
